import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ToastController, IonHeader, IonToolbar, IonTitle, IonContent,
  IonCard, IonCardHeader, IonCardTitle, IonCardContent, IonCardSubtitle,
  IonButton, IonIcon } from '@ionic/angular/standalone';
import { addIcons } from 'ionicons';
import { starOutline, documentOutline, peopleOutline, timeOutline } from 'ionicons/icons';
import { FilaService } from '../../services/fila.service';
import { Senha, TipoSenha } from '../../models/senha.model';
import { TipoLabelPipe } from '../../shared/pipes/tipo-label.pipe';

@Component({
  selector: 'app-totem',
  templateUrl: './totem.page.html',
  styleUrls: ['./totem.page.scss'],
  standalone: true,
  imports: [CommonModule, TipoLabelPipe,
    IonHeader, IonToolbar, IonTitle, IonContent,
    IonCard, IonCardHeader, IonCardTitle, IonCardContent, IonCardSubtitle,
    IonButton, IonIcon],
})
export class TotemPage {
  ultimaSenha: Senha | null = null;

  constructor(private filaService: FilaService, private toastCtrl: ToastController) {
    addIcons({ starOutline, documentOutline, peopleOutline, timeOutline });
  }

  get expedienteAberto(): boolean { return this.filaService.expedienteAberto; }

  async emitir(tipo: TipoSenha) {
    const senha = this.filaService.emitirSenha(tipo);
    if (!senha) {
      const toast = await this.toastCtrl.create({ message: 'Fora do horário de atendimento.', duration: 2000, color: 'danger' });
      await toast.present();
      return;
    }
    this.ultimaSenha = senha;
  }
}
<ion-header>
  <ion-toolbar color="primary">
    <ion-title>🏥 Totem de Atendimento</ion-title>
  </ion-toolbar>
</ion-header>

<ion-content class="ion-padding">
  <div *ngIf="!expedienteAberto" class="fora-expediente">
    <ion-icon name="time-outline" size="large"></ion-icon>
    <h2>Fora do expediente</h2>
    <p>Atendimento disponível das <strong>07:00</strong> às <strong>17:00</strong>.</p>
  </div>
  <div *ngIf="expedienteAberto">
    <ion-card>
      <ion-card-header>
        <ion-card-title>Selecione o tipo de atendimento</ion-card-title>
      </ion-card-header>
      <ion-card-content>
        <ion-button expand="block" color="danger" (click)="emitir('SP')" class="btn-tipo">
          <ion-icon slot="start" name="star-outline"></ion-icon>
          Prioritário (SP)
        </ion-button>
        <ion-button expand="block" color="warning" (click)="emitir('SE')" class="btn-tipo">
          <ion-icon slot="start" name="document-outline"></ion-icon>
          Retirada de Exames (SE)
        </ion-button>
        <ion-button expand="block" color="success" (click)="emitir('SG')" class="btn-tipo">
          <ion-icon slot="start" name="people-outline"></ion-icon>
          Geral (SG)
        </ion-button>
      </ion-card-content>
    </ion-card>
    <ion-card *ngIf="ultimaSenha" class="senha-card">
      <ion-card-header>
        <ion-card-subtitle>Sua senha</ion-card-subtitle>
        <ion-card-title class="numero-senha">{{ ultimaSenha.numero }}</ion-card-title>
      </ion-card-header>
      <ion-card-content>
        <p><strong>Tipo:</strong> {{ ultimaSenha.tipo | tipoLabel }}</p>
        <p><strong>Emitida em:</strong> {{ ultimaSenha.emitidaEm | date:'HH:mm:ss' }}</p>
        <p *ngIf="ultimaSenha.descartada" class="descartada">⚠️ Senha descartada automaticamente.</p>
        <p *ngIf="!ultimaSenha.descartada" class="aguarde">✅ Aguarde ser chamado no painel.</p>
      </ion-card-content>
    </ion-card>
  </div>
</ion-content>
